export function rowSelectLinkWithParents(state) {
    if (state.kind === "isolated")
        return { kind: "linked", children: new Map(), selected: false };
    const makeWithParents = (parent, node, key) => {
        const nodeWithParent = { ...node, parent };
        parent.children?.set(key, nodeWithParent);
        if (node.children) {
            nodeWithParent.children = new Map();
            node.children.forEach((x, k) => makeWithParents(nodeWithParent, x, k));
        }
    };
    const root = { ...state, children: new Map() };
    state.children.forEach((x, k) => makeWithParents(root, x, k));
    return root;
}
